def jogo_da_vida(matriz, q):
    n = len(matriz)
    for _ in range(q):
        novo_matriz = [['0'] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                vizinhos = 0
                for x in range(max(0, i - 1), min(n, i + 2)):
                    for y in range(max(0, j - 1), min(n, j + 2)):
                        if (x, y) != (i, j) and matriz[x][y] == '1':
                            vizinhos += 1
                if matriz[i][j] == '1':
                    if vizinhos == 2 or vizinhos == 3:
                        novo_matriz[i][j] = '1'
                    else:
                        novo_matriz[i][j] = '0'
                else:
                    if vizinhos == 3:
                        novo_matriz[i][j] = '1'
                    else:
                        novo_matriz[i][j] = '0'
        matriz = novo_matriz
    return matriz

if __name__ == "__main__":
    n, q = map(int, input().split())
    matriz = []
    for _ in range(n):
        matriz.append(list(input()))

    resultado = jogo_da_vida(matriz, q)

    for linha in resultado:
        print("".join(linha))

