def solve():
    n, q = map(int, input().split())
    digits = list(map(int, input().split()))

    for _ in range(q):
        l, r = map(int, input().split())
        sub_digits = digits[l-1:r]

        potential = 0
        for i in range(len(sub_digits)):
            for j in range(len(sub_digits)):
                if i != j:
                    potential += (sub_digits[i] * 10) + sub_digits[j]

        if len(sub_digits) == 0:
            print(0)
        else:
            print(potential)

solve()

def solve():
    n, m = map(int, input().split())
    matrix = []
    for _ in range(n):
        matrix.append(list(map(int, input().split())))

    def get_max_power(start_row, start_col):
        visited = set()
        q = [(start_row, start_col, matrix[start_row][start_col])]

        max_power = 0

        while q:
            row, col, current_power = q.pop(0)

            max_power = max(max_power, current_power)

            visited.add((row, col))

            # Possible moves: up, down, left, right
            moves = [(0, 1), (0, -1), (1, 0), (-1, 0)]

            for dr, dc in moves:
                new_row, new_col = row + dr, col + dc

                if 0 <= new_row < n and 0 <= new_col < m and (new_row, new_col) not in visited:
                    if matrix[new_row][new_col] <= current_power:
                        q.append((new_row, new_col, current_power + matrix[new_row][new_col]))
                        visited.add((new_row, new_col))

        return max_power

    result = []
    for i in range(n):
        row_result = []
        for j in range(m):
            row_result.append(get_max_power(i, j))
        result.append(row_result)

    for row in result:
        print(*row)

solve()

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    if len(set(a)) == 1:
        print(0)
        return

    q = [(a, 0)]
    visited = {tuple(a)}

    while q:
        curr_a, steps = q.pop(0)

        if len(set(curr_a)) == 1:
            print(steps)
            return

        for l in range(n):
            for r in range(l, n):

                valid = True
                first_height = curr_a[l]
                for i in range(l, r + 1):
                    if curr_a[i] != first_height:
                        valid = False
                        break

                if valid:
                    next_a = curr_a[:]
                    for i in range(l, r + 1):
                        next_a[i] += 1

                    if tuple(next_a) not in visited:
                        q.append((next_a, steps + 1))
                        visited.add(tuple(next_a))

solve()

def solve():
    n, x1, x2 = map(int, input().split())
    lines = []
    for _ in range(n):
        a, b = map(int, input().split())
        lines.append((a, b))

    count = 0
    for i in range(n):
        for j in range(i + 1, n):
            a1, b1 = lines[i]
            a2, b2 = lines[j]

            if a1 == a2:
                continue

            x = (b2 - b1) / (a1 - a2)

            if x1 <= x <= x2:
                count += 1

    print(count)

solve()

def solve():
    n = int(input())
    p = list(map(int, input().split()))
    q = int(input())

    parent = list(p)

    def find(i):
        if parent[i-1] == i:
            return i
        return find(parent[i-1])

    def get_ancestor(node, k):
        curr = node
        for _ in range(k):
            curr = parent[curr-1]
        return curr

    for _ in range(q):
        op = list(map(int, input().split()))

        if op[0] == 1:
            v = op[1]
            k = op[2]
            print(get_ancestor(v, k))
        else:
            v = op[1]
            for i in range(2, n + 1):
                if find(i) != i:
                    continue

                curr = i
                while parent[curr-1] != curr:
                    curr = parent[curr-1]

                if curr == v:
                    parent[i-1] = v

solve()
